function NoMetadataEntityComponent({ utilities }) {
  const [data, setData] = useState([]);

  useEffect(() => {
    async function loadData() {
      const result = await utilities.rv.RunView({ EntityName: 'NonExistentTestEntity12345' });
      if (result?.Success) {
        setData(result.Results);
      }
    }
    loadData();
  }, []);

  return (
    <div>
      <h3>Data</h3>
      {data.map((item, i) => (
        <div key={i}>{JSON.stringify(item)}</div>
      ))}
    </div>
  );
}
